import API from "./api";

// ===============================
// AUTH APIs
// ===============================
export const login = async (data) => {
try {
const res = await API.post("/auth/login", data);
return res.data;
} catch (err) {
console.error("Login Error:", err);
return null;
}
};

export const register = async (data) => {
try {
const res = await API.post("/auth/register", data);
return res.data;
} catch (err) {
console.error("Register Error:", err);
return null;
}
};

// ===============================
// USER APIs
// ===============================
export const getProfile = async (username) => {
try {
const res = await API.get(`/user/${username}`);
return res.data;
} catch (err) {
console.error("Profile Error:", err);
return null;
}
};

// ===============================
// CRICKET APIs
// ===============================
export const getLiveMatches = async () => {
try {
const res = await API.get("/cricket/live");
return res.data;
} catch (err) {
console.error("Live Matches Error:", err);
return [];
}
};

export const getPlayerStats = async (name) => {
try {
const res = await API.get(`/cricket/player?name=${name}`);
return res.data;
} catch (err) {
console.error("Player Stats Error:", err);
return null;
}
};

export const getSchedule = async () => {
try {
const res = await API.get("/cricket/schedule");
return res.data;
} catch (err) {
console.error("Schedule Error:", err);
return [];
}
};

// ===============================
// CHAT API
// ===============================
export const sendChat = async (message) => {
try {
const res = await API.post("/chat", { message });
return res.data;
} catch (err) {
console.error("Chat Error:", err);
return null;
}
};

// ===============================
// INSIGHTS API
// ===============================
export const getInsights = async (player) => {
try {
const res = await API.get(`/insights?player=${player}`);
return res.data;
} catch (err) {
console.error("Insights Error:", err);
return null;
}
};

// ===============================
// KNOWLEDGE API
// ===============================
export const searchKnowledge = async (query) => {
try {
const res = await API.get(`/knowledge?q=${query}`);
return res.data;
} catch (err) {
console.error("Knowledge Error:", err);
return null;
}
};
